define('local_moodle_pg_content/soundAmplification', ['jquery', 'jqueryui', 'cssLoader', 'local_moodle_pg_content/fabric'], function($, jqueryui, cssLoader) {

    // return module instance

        var _config = {
            canvasClass: 'cmlc-canvasAmplification',
            canvasSize: {width: 600, height: 300},
            sliderYClass: '#cmlc-slider-y',
            sliderXClass: '#cmlc-slider-x',
            resultClass: '.cmlc-amplification',
            defaultA: 30,
            defaultR: 1.3
        };

        var _tpl =
            '<div class="cmlc-soundAmplification">' +
                '<canvas id="' + _config.canvasClass + '"></canvas>' +

                '<div class="cmlc-slider-y-content">A<sub>1</sub> / A<sub>2</sub> = <span>'+ _config.defaultA +'</span></div>' +
                '<div class="cmlc-slider-left">15</div><div class="cmlc-slider-right">45</div>' +
                '<div class="ui-helper-clearfix"></div> ' +
                '<div id="cmlc-slider-y"></div>' +

                '<br /><br />' +
                '<div class="cmlc-slider-x-content">r<sub>1</sub> / r<sub>2</sub> = <span>' + _config.defaultR + '</span></div>' +
                '<div class="cmlc-slider-left">0.65</div><div class="cmlc-slider-right">1.95</div>' +
                '<div class="ui-helper-clearfix"></div>' +
                '<div id="cmlc-slider-x"></div>' +

                '<h2 class="cmlc-amplification"><img src="/moodle/local/moodle_pg_content/images/ftims-dzwiek/rownanie_wzmocnienia.png"> <span></span></h2>' +

            '</div>';

        var canvas;

        var _objArr = {};

        var _YstartPoint = 65;
        var _tmpY = _config.defaultA;
        var _tmpX = _config.defaultR;

        var _modConfig;
        var _module;
        var _$module;
        var _init = function () {

            //load CSS
            cssLoader('/moodle/local/moodle_pg_content/css/cmlc-soundAmplification.css');
            cssLoader('/moodle/local/moodle_pg_content/css/jquery-ui.min.css');
            cssLoader('/moodle/local/moodle_pg_content/css/jquery-ui.theme.min.css');



            // append tpl to content
            _$module.html("").append(_tpl);

            // create canvas object
            canvas = new fabric.Canvas(_config.canvasClass);
            canvas.setDimensions(_config.canvasSize);

            // draw points and line
            _createLinePoints();

            // load SVG and text
            _loadSVG('right', '/moodle/local/moodle_pg_content/images/ftims-dzwiek/ucho-2.svg', {left: 330, top: 100}, 4); // prawa
            canvas.add(new fabric.Text('A2', {left: 380, top: 120, selectable: false, fontSize: 18}));

            _loadSVG('bg', '/moodle/local/moodle_pg_content/images/ftims-dzwiek/ucho-3.svg', {left: 220, top: 40}, 5); // tlo
            _loadSVG('left', '/moodle/local/moodle_pg_content/images/ftims-dzwiek/ucho-1.svg', {left: 215, top: 110}, 6); // lewa
            canvas.add(new fabric.Text('A1', {left: 170, top: 170, selectable: false, fontSize: 18}));

            canvas.add(new fabric.Text('r1', {left: 200, top: 80, selectable: false, fontSize: 15, fill: 'red'}));
            canvas.add(new fabric.Text('r2', {left: 320, top: 70, selectable: false, fontSize: 15, fill: 'red'}));

            // create sliders
            _createSliders();

            // caluclate result
            _calculateResult();

        };

        var _createLinePoints = function () {

            var lleft = _createLine("lleft", [250, 135, 260, _YstartPoint]);
            var lright = _createLine("lright", [305, 135, 260, _YstartPoint]);

            _createPoint('ptop', lleft.get('x2'), lleft.get("y2"), 16);

            canvas.renderAll();
        };

        var _createLine = function (id, coords, zindex) {
            var line = new fabric.Line(coords, {
                fill: 'red',
                stroke: 'red',
                strokeWidth: 2,
                selectable: false,
                originX: 'center',
                originY: 'center',
                id: id,
                opacity: 0
            });
            canvas.add(line);
            return line;
        }

        var _createPoint = function (id, left, top, zindex) {
            var c = new fabric.Circle({
                left: left,
                top: top,
                strokeWidth: 2,
                radius: 5,
                fill: '#fff',
                stroke: '#666',
                id: id,
                originX: 'center',
                originY: 'center'
            });
            c.hasControls = c.hasBorders = c.selectable = false;
            canvas.add(c);
            return c;
        };

        var _loadSVG = function (id, file, startPoint, zindex) {

            fabric.loadSVGFromURL(file, function (objects, options) {
                var obj = fabric.util.groupSVGElements(objects, options);
                obj.hasControls = false;
                obj.hasBorders = false;
                obj.selectable = false;
                obj.centeredScaling = true;

                obj.scale(3.5);
                obj.set('id', id)
                obj.set(startPoint).setCoords();

                canvas.add(obj);
                obj.sendToBack();
                obj.moveTo(zindex);
                canvas.renderAll();
            });

        }

        var _createSliders = function () {

            // create slider
            var _sliderY = _$module.find(_config.sliderYClass);
            _sliderY.slider({
                min: 15,
                max: 45,
                value: 30,
                slide: function (event, ui) {
                    $('.cmlc-slider-y-content span').html(ui.value);
                    _changeY(ui.value);
                }
            });

            var _sliderX = _$module.find(_config.sliderXClass);
            _sliderX.slider({
                min: 0.65,
                max: 1.95,
                value: 1.3,
                step: 0.01,
                slide: function (event, ui) {
                    $('.cmlc-slider-x-content span').html(ui.value);
                    _changeX(ui.value);
                }
            });

        };

        var _changeY = function (ratio) {

            _tmpY = ratio;

            var a1 = _findObject('left');
            var staticRatio = ratio / 30;
            a1.scale(2 + staticRatio);
            canvas.renderAll();

            _calculateResult();
        };

        var _changeX = function (ratio) {

            var ptop = _findObject("ptop");
            var lleft = _findObject("lleft");
            var lright = _findObject("lright");

            _tmpX = ratio;

            lleft.set({opacity: 0.5}).bringToFront();
            lright.set({opacity: 0.5}).bringToFront();
            ptop.bringToFront();

            var y = _YstartPoint;

            var a = (ratio / 1.3);
            var step = (a % 1) * 70;

            if (a > 1) {
                ptop.set({top: (y - step)});
                lleft.set({y2: (y - step)});
                lright.set({y2: (y - step)});
            } else if (a == 1) {
                ptop.set({top: y});
                lleft.set({y2: y});
                lright.set({y2: y});
            } else {
                step = (1 - ( a % 1)) * 70;
                ptop.set({top: (y + step)});
                lleft.set({y2: (y + step)});
                lright.set({y2: (y + step)});
            }

            canvas.renderAll();

            _calculateResult();
        }

        var _calculateResult = function () {
            _$module.find(_config.resultClass + ' > span').html((_tmpX * _tmpY).toFixed(2));

        };

        var _findObject = function (id) {

            if (_objArr[id] != undefined) {
                return _objArr[id];
            } else {
                var tmpObjects = canvas.getObjects();
                for (var i = 0; i < tmpObjects.length; i++) {
                    if (tmpObjects[i].id == id) {
                        _objArr[id] = tmpObjects[i];
                        return tmpObjects[i];
                    }
                }
            }

        }

        return {
            init: function (module, modConfig) {
                _module = module;
                _$module = $(_module);
                _modConfig = modConfig;
                _init();
            }
        };


});
