define('local_moodle_pg_content/waveExamples', ['jquery', 'jqueryui', 'cssLoader', 'local_moodle_pg_content/jquery.flot'], function ($, jqueryui, cssLoader) {

    // return module instance

    var _config = {
        name: "",
        description: "",
        configClass: '.config',
        plotId: '#cmlc-flotCanvas',
        exampleListClass: '.cmlc-examples-list',
        defaults: {
            a: 1,
            f: 500,
            L: 0,
            v: 300,
            order: 1,
            ar: 1,
            fi: 0,
            fr: 1,
            showSeries: [true, false, false],
            hideAllControls: false,
            animation: true
        },
        params: {}
    };

    var _tpl =
        '<div class="cmlc-waveExamples">' +
        '<div class="cmlc-examples-list"></div>' +
        '<div class="cmlc-examples-description"></div>' +

        '<div id="cmlc-flotCanvas" style="width:600px; height: 280px;"></div>' +

        '<div class="cmlc-waveOptions">' +

        '<div><button class="startstop">Stop</button></div><br />' +
        '<b>Fale poruszają się:</b><br />' +
        '<label><input type="radio" name="order" class="orderPlus" value="1"> w jednym kierunku</label><br />' +
        '<label><input type="radio" name="order" class="orderMinus" value="-1"> w przeciwnych kierunkach</label>' +

        '<br /><br /><b>Pokaż:</b><br />' +
        '<label><input type="checkbox" name="f1"> f1</label><br />' +
        '<label><input type="checkbox" name="f2"> f2</label><br />' +
        '<label><input type="checkbox" name="f3"> f1 + f2</label><br />' +

        '<br /><b>Stosunek amplitud:</b>' +
        '<div class="cmlc-slider-ar-content"><span>' + _config.defaults.ar + '</span></div><br />' +
        '<div class="cmlc-slider-ar"></div>' +
        '<div class="cmlc-slider-left">1</div><div class="cmlc-slider-right">2</div>' +
        '<div class="ui-helper-clearfix"></div>' +

        '<br /><b>Różnica faz:</b>' +
        '<div class="cmlc-slider-fi-content"><span>' + _config.defaults.fi + '</span></div><br />' +
        '<div class="cmlc-slider-fi"></div>' +
        '<div class="cmlc-slider-left">0</div><div class="cmlc-slider-right">pi</div>' +
        '<div class="ui-helper-clearfix"></div>' +

        '<br /><b>Stosunek częstotliwości f2/f1:</b>' +
        '<div class="cmlc-slider-fr-content"><span>' + _config.defaults.fr + '</span></div><br />' +
        '<div class="cmlc-slider-fr"></div>' +
        '<div class="cmlc-slider-left">0.75</div><div class="cmlc-slider-right">1.25</div>' +
        '<div class="ui-helper-clearfix"></div>' +


        '</div>' +

        '</div>';

    var _container;
    var _plot;
    var _activeExample;
    var _examples;
    var _interval;
    var _play = true;


    var _modConfig;
    var _module;
    var _$module;
    var _init = function () {

        //load CSS
        cssLoader('/moodle/local/moodle_pg_content/css/cmlc-waveExamples.css');
        cssLoader('/moodle/local/moodle_pg_content/css/jquery-ui.min.css');
        cssLoader('/moodle/local/moodle_pg_content/css/jquery-ui.theme.min.css');

        // load config
        _loadConfig();

        // append tpl to content
        _$module.html("").append(_tpl);

        // get plot container
        _container = _$module.find(_config.plotId);

        _registerEvents();

        // write examples
        _writeExamplesList();

    };

    var t = 0;

    var _showExample = function () {

        var series = _prepareData();
        _plot = $.plot(_container, series, {
            yaxis: {
                max: _config.params.a * 3 + 1,
                min: -(_config.params.a * 3 + 1)
            },
            xaxis: {
                ticks: null
            }
        });
        _container.show();

        _startAnimation();
    };

    var _startAnimation = function () {
        _interval = setInterval(function () {
            if (_play) {
                t = t + 0.00000015;
            }
            _plot.setData(_prepareData());
            _plot.draw();
        }, 65);
    }

    var _stopAnimation = function () {
        _interval !== undefined && clearInterval(_interval);
    }

    var _prepareData = function () {

        // calculate first function
        var A = _config.params.a,
            f = _config.params.f,
            w = 2 * 3.14 * f,
            v = _config.params.v,
            L = _config.params.L;

        // calculate second function
        var A2 = _config.params.ar * A,
            L = _config.params.fi,
            f2 = f * _config.params.fr,
            w2 = 2 * 3.14 * f2;

        var dataSet = [[], [], []];

        for (var x = 0; x < 20; x += 0.1) {
            var f1 = A * Math.sin((v * t + x) * w);
            var f2 = A2 * Math.sin((v * t + _config.params.order * x) * w2 + L);
            var f3 = f1 + f2;

            if (_config.params.showSeries[0]) {
                dataSet[0].push([x, f1]);
            }
            if (_config.params.showSeries[1]) {
                dataSet[1].push([x, f2]);
            }
            if (_config.params.showSeries[2]) {
                dataSet[2].push([x, f3]);
            }

        }

        return dataSet;

    }

    var _writeExamplesList = function () {

        var div = _$module.find(_config.exampleListClass);

        var ul = $("<ul></ul>").appendTo(div);

        for (var i = 0; i < _examples.length; i++) {
            ul.append('<li><a href="#" data-id="' + i + '">' + _examples[i].name + '</a></li>');
        }

        // from span to button
        ul.find('a').on('click', function () {
            _selectExample($(this).data('id'));

            _$module.find('.cmlc-examples-description').html(_config.params.description);

            return false;
        });

        // select first example if is only one
        if (_examples.length == 1) {
            _selectExample(0);
            return;
        } else {
            // hide options on start
            _$module.find('.cmlc-waveOptions').hide();
            _container.hide();
        }

    };

    var _selectExample = function (id) {
        _activeExample = id;

        // disable interval
        _stopAnimation();

        // copy settings
        $.extend(_config.params, _config.defaults, _examples[id]);

        // PREPARE WORKSPACE
        // order
        _config.params.order === 1 && _$module.find('.orderPlus').attr("checked", "checked");
        _config.params.order === -1 && _$module.find('.orderMinus').attr("checked", "checked");

        // show series
        for (var j = 0; j < 3; j++) {
            _$module.find("input[type=checkbox][name=f" + (j + 1) + "]").prop("checked", _config.params.showSeries[j]);
        }

        // turn on/off animation
        if (!_config.params.animation) {
            _play = false;
            _$module.find('.startstop .ui-button-text').html("Start");
        } else {
            _play = true;
            _$module.find('.startstop .ui-button-text').html("Stop");
        }

        // set sliders
        _$module.find('.cmlc-slider-ar').slider("value", _config.params.ar);
        _$module.find('.cmlc-slider-fi').slider("value", _config.params.fi);
        _$module.find('.cmlc-slider-fr').slider("value", _config.params.fr);

        // hide all controls
        if (_config.params.hideAllControls) {
            _$module.find(".cmlc-waveOptions").hide();
        } else {
            _$module.find(".cmlc-waveOptions").show();
        }

        _showExample();
    };

    var _registerEvents = function () {

        _$module.find('.startstop').button().click(function () {
            if (_play) {
                _play = false;
                $(this).find('.ui-button-text').html("Start");
            } else {
                _play = true;
                $(this).find('.ui-button-text').html("Stop");
            }
        });

        _$module.find('input[type=checkbox]').change(function () {
            var newCheck = $(this).is(":checked");
            switch ($(this).attr('name')) {
                case "f1":
                    _config.params.showSeries[0] = newCheck;
                    break;
                case "f2":
                    _config.params.showSeries[1] = newCheck;
                    break;
                case "f3":
                    _config.params.showSeries[2] = newCheck;
                    break;
            }
            return;
        });

        _$module.find('input[name=order]').on('change', function () {
            _config.params.order = parseInt($(this).val());
        });

        _$module.find('.cmlc-slider-ar').slider({
            min: 1,
            max: 2,
            value: _config.defaults.ar,
            step: 0.1,
            slide: function (event, ui) {
                _config.params.ar = ui.value;
                _$module.find('.cmlc-slider-ar-content span').html(ui.value);
            }
        });

        _$module.find('.cmlc-slider-fi').slider({
            min: 0,
            max: 3.14,
            value: _config.defaults.fi,
            step: 0.01,
            slide: function (event, ui) {
                _config.params.fi = ui.value;
                _$module.find('.cmlc-slider-fi-content span').html(ui.value);
            }
        });

        _$module.find('.cmlc-slider-fr').slider({
            min: 0.76,
            max: 1.26,
            value: _config.defaults.fr,
            step: 0.02,
            slide: function (event, ui) {
                _config.params.fr = ui.value;
                _$module.find('.cmlc-slider-fr-content span').html(ui.value);
            }
        });

    };

    var _loadConfig = function () {

        var _tmpConfig = _$module.find(_config.configClass).html();
        _examples = JSON.parse(_tmpConfig);

    }

    return {
        init: function (module, modConfig) {
            _module = module;
            _$module = $(_module);
            _modConfig = modConfig;
            _init();
        }
    };


});
define('local_moodle_pg_content/soundGenerator', ['jquery', 'jqueryui', 'local_moodle_pg_content/timbre', 'cssLoader'], function($, jqueryui, timbre, cssLoader) {

    // return module instance

        var _config = {
            defaultHzValue: 1000,
            buttonClass: ".cmlc-sg-play",
            freqInputClass: ".cmlc-sg-freq-value",
            sliderClass: "#cmlc-slider",
            showPiano: true
        };


        var _tpl =
                '<div class="cmlc-soundGenerator">' +
                '<div class="cmlc-sg-left"><input type="text" class="cmlc-sg-freq-value" value="' + _config.defaultHzValue  + '"> Hz </div>' +
                '<div class="cmlc-sg-right"><div id="cmlc-slider"></div><span class="cmlc-slider-left">10 Hz</span><span class="cmlc-slider-right">18 kHz</span></div>' +
                '<div style="text-align: center;"><button class="cmlc-sg-play">Play</button></div>' +
                '<div class="cmlc-piano"></div>' +
                '</div>'
            ;


        var _play = false;
        var _timbre = T("sin", { freq: _config.defaultHzValue });

        var _$input;
        var _slider;

        var _modConfig;
        var _module;
        var _$module;
        var _init = function() {

            //load CSS
            cssLoader('/moodle/local/moodle_pg_content/css/cmlc-soundGenerator.css');
            cssLoader('/moodle/local/moodle_pg_content/css/jquery-ui.min.css');
            cssLoader('/moodle/local/moodle_pg_content/css/jquery-ui.theme.min.css');

            //T("sin", {freq:880, mul:0.5}).play();

            _$module.html("").append(_tpl);

            // find input
            _$input = _$module.find( _config.freqInputClass );
            // create spinner

            _$input.spinner({
                min: 10,
                max: 18000,
                spin: function( event, ui ) {
                    _slider.slider("value", ui.value);
                    _changeFreq( ui.value );
                }
            });

            // create slider
            _slider = _$module.find( _config.sliderClass);
            _slider.slider({
                min: 10,
                max: 18000,
                value: _config.defaultHzValue,
                slide: function( event, ui ) {
                    _$input.val( ui.value );
                    _changeFreq( ui.value );
                }
            });

            // create button
            _$module.find( _config.buttonClass).button({
                icons: {
                    primary: "ui-icon-play"
                }
            }).on('click', function() {
                _startStop();
            });

            // register onchange
            _$input.on('keyup change', function() {
                _changeFreq( $(this).val() );
                _slider.slider("value", $(this).val());
            });

            var showPiano = _modConfig['piano'];
            if ( showPiano != undefined && showPiano !== '' ) {
                _config.showPiano = showPiano;
            }

            if ( _config.showPiano ) {
                // create piano
                _pianoCreate();
            }



        };

        var _changeFreq = function( newFreq ) {
            _timbre.set({freq: parseInt(newFreq)});
        };

        var _startStop = function() {

            var freq = _$module.find( _config.freqInputClass ).val();

            if ( _play ) {
                _timbre.pause();
                _play = false;
                _$module.find( _config.buttonClass ).find('.ui-button-text').html('Play');
                _$module.find( _config.buttonClass ).find('.ui-button-icon-primary').removeClass('ui-icon-pause').addClass('ui-icon-play');
            } else {
                _timbre.play();
                _play = true;
                _$module.find( _config.buttonClass ).find('.ui-button-text').html('Pause');
                _$module.find( _config.buttonClass ).find('.ui-button-icon-primary').removeClass('ui-icon-play').addClass('ui-icon-pause');
            }

        };

        var _freqTable = [
            [65.406392, 73.416193, 82.406890, 87.307059, 97.998860, 110.000001, 123.470827],
            [130.812784, 146.832385, 164.813780, 174.614118, 195.997720, 220.000002, 246.941653],
            [261.625568, 293.664771, 329.627560, 349.228235, 391.995440, 440.000005, 493.883306],
            [523.251136, 587.329542, 659.255121, 698.456470, 783.990880, 880.000009, 987.766613],
            [1046.502272, 1174.659084, 1318.510241, 1396.912940, 1567.981760, 1760.000018, 1975.533225]
        ];
        var _freqIsTable = [
            [69.295658, 77.781747, 0, 92.498607, 103.826175, 116.540942],
            [138.591317, 155.563493, 0, 184.997213, 207.652351, 233.081883],
            [277.182634, 311.126987, 0, 369.994427, 415.304702, 466.163766],
            [554.365268, 622.253974, 0, 739.988853, 830.609404, 932.327533],
            [1108.730535, 1244.507948, 0, 1479.977706, 1661.218807, 1864.655065]
        ];

        var _pianoCreate = function() {

            // create octave
            for ( var o = 0; o < 5; o++ ) {
                var _tmpOctave = '<div class="cmlc-octave">';
                for ( var k = 0; k <= 6; k++ ) {
                    _tmpOctave += '<span class="cmlc-octave-key cmlc-piano-play" data-freq="'+_freqTable[o][k]+'"></span>';

                    if ( k != 2 && k != 6 ) {
                        _tmpOctave += '<span class="cmlc-octave-key-is cmlc-piano-play" style="left: '+ parseInt((k * 21) + 16) +'px" data-freq="'+_freqIsTable[o][k]+'"></span>';
                    }
                }
                _tmpOctave += '</div>';

                _$module.find('.cmlc-piano').append(_tmpOctave);
            }


            _$module.find('.cmlc-piano-play').on('click', function() {
                var _tmpF = $(this).data('freq')
                _changeFreq( _tmpF );
                _slider.slider("value", _tmpF);
                _$input.val( _tmpF );
            });

        };

        return {
            init: function( module, modConfig ) {

                _module = module;
                _$module = $(_module);
                _modConfig = modConfig;

                _init();
            }
        };

    
});
