                   '</div>';

        var _points = [];

        var _modConfig;
        var _module;
        var _$module;
        var _init = function() {

            var hoverPointColor = _modConfig['config'].hoverColor;
            if ( hoverPointColor != undefined && hoverPointColor !== '' ) {
                _config.hoverPointColor = hoverPointColor;
            }
            var pointSize = _modConfig['config'].pointSize;
            if ( pointSize !== undefined && pointSize !== '' ) {
                _config.pointSize = pointSize;
            }
            var pointColor = _modConfig['config'].color;
            if ( pointColor !== undefined && pointColor !== '' ) {
                _config.pointColor = pointColor;
            }

            var pointStyle = _modConfig['config'].pointStyle;
            if ( pointStyle !== undefined && pointStyle !== '' ) {
                _config.pointStyle = pointStyle;
            }

            // loadCSS
            cssLoader('/moodle/local/moodle_pg_content/css/cmlc-image-description.css');

            // read points
            _readPoints();
            // clear html
            _prepareHtml();
            // draw image
            _findImage();
            // draw points
            _drawPoints();

        };

        var _prepareHtml = function() {
            _$module.html("").append(_tpl);
        };

        var _readPoints = function() {

          // scan module
          var points = _$module.find('div');
          var i = 0;
          points.each(function() {
              var point = $(this);
              _points[i] = {
                  x: point.data().x,
                  y: point.data().y,
                  desc: point.html(),
                  title: point.attr('title')
              };
              i++;
          });

        };

        var _drawPoints = function() {

            for (var j = 0, l = _points.length; j < l; j++) {

                var title = "";
                if ( _points[j].title != undefined )
                {
                    title = 'title="'+_points[j].title+'"';
                }

                if ( _config.pointStyle == 'number' ) {
                    _$module
                        .find('.' + _config.imageClassDefinition )
                        .append('<div data-point-id="' + j + '" '+title+' class="' + _config.hoverPointClassDefinition + '" style="width: '+ _config.pointSize +'px;  line-height: '+_config.pointSize+'px; font-size: '+(_config.pointSize-4) +'px; margin-left: -'+ _config.pointSize/2 +'px; margin-top: -'+ _config.pointSize/2 +'px; left: ' + _points[j].x + 'px; top: ' + _points[j].y + 'px">'+ (j+1) +'</div>');
                } else {
                    _$module
                        .find('.' + _config.imageClassDefinition )
                        .append('<div data-point-id="' + j + '" '+title+' class="' + _config.hoverPointClassDefinition + '" style="width: '+ _config.pointSize +'px; height: '+ _config.pointSize +'px; margin-left: -'+ _config.pointSize/2 +'px; margin-top: -'+ _config.pointSize/2 +'px; background: ' + _config.pointColor + '; left: ' + _points[j].x + 'px; top: ' + _points[j].y + 'px"></div>');
                }

            };

            if ( _config.pointStyle == 'number' ) {
                _$module.find('.' + _config.hoverPointClassDefinition).click(function () {
                    _$module.find('.' + _config.hoverPointClassDefinition).removeClass(_config.pointHoverClass).css("color", _config.pointColor);
                    $(this).addClass(_config.pointHoverClass).css("color", _config.hoverPointColor);

                    var id = $(this).data("point-id");
                    _$module.find('.' + _config.descClassDefinition).show().html(_points[id].desc);
                });
            } else {
                _$module.find('.' + _config.hoverPointClassDefinition).click(function () {
                    _$module.find('.' + _config.hoverPointClassDefinition).removeClass(_config.pointHoverClass).css("background", _config.pointColor);
                    $(this).addClass(_config.pointHoverClass).css("background", _config.hoverPointColor);

                    var id = $(this).data("point-id");
                    _$module.find('.' + _config.descClassDefinition).show().html(_points[id].desc);
                });
            };

        };

        var _findImage = function() {

            var imageSrc = _modConfig['config'].image;

            if ( imageSrc !== undefined && imageSrc !== '' ) {
                $.ajax({
                    url: imageSrc,
                    type:'HEAD',
                    error: function()
                    {
                        _$module.html('Obraz nie istnieje.');
                    },
                    success: function()
                    {
                        // create image
                        var newImage = document.createElement("img");
                        newImage.setAttribute("src", imageSrc);

                        // pass to html
                        _$module.find( '.' + _config.imageClassDefinition).append(newImage);
                    }
                });
            }

        };

        return {
            init: function( module, modConfig ) {

                _module = module;
                _$module = $(_module);
                _modConfig = modConfig;

                _init();
            }
        };


});
